const now = Date.now();
const DAY_MS = 86400000;
const items = $input.all().map(r => r.json);

const stuckCases = items.filter(c => (c['Missing items count'] || 0) > 0);
const waitingAppraiser = items.filter(c => c['Current stage'] === 'waiting-appraiser');
const bankNegotiation = items.filter(c => c['Current stage'] === 'bank-negotiation');
const newSinceYesterday = items.filter(c => {
  const mod = new Date(c['Last modified'] || 0).getTime();
  return mod > now - DAY_MS;
});

const lines = ['🗂️ *ברייפינג יומי — KeyPoint*', `📅 ${new Date().toLocaleDateString('he-IL')}`, ''];

if (newSinceYesterday.length) {
  lines.push(`🆕 *תיקים שעודכנו מאתמול* (${newSinceYesterday.length})`);
  newSinceYesterday.slice(0, 5).forEach(c => lines.push(`  • ${c['Lead name']} — ${c['Current stage']}`));
  lines.push('');
}

if (stuckCases.length) {
  lines.push(`🔴 *תיקים תקועים — מסמכים חסרים* (${stuckCases.length})`);
  stuckCases.slice(0, 8).forEach(c => lines.push(`  • ${c['Lead name']} — ${c['Missing items count']} חסרים`));
  lines.push('');
}

if (waitingAppraiser.length) {
  lines.push(`🏠 *ממתין לשמאי* (${waitingAppraiser.length})`);
  waitingAppraiser.forEach(c => lines.push(`  • ${c['Lead name']}`));
  lines.push('');
}

if (bankNegotiation.length) {
  lines.push(`🏦 *משא ומתן עם בנק* (${bankNegotiation.length})`);
  bankNegotiation.forEach(c => lines.push(`  • ${c['Lead name']}`));
  lines.push('');
}

lines.push(`סה"כ תיקים פתוחים: ${items.length}`);

return [{ json: { message: lines.join('\n'), caseCount: items.length } }];
